// ② 解析 LINE 事件，篩選關鍵字：下載、衛教、簡報
const body = $input.first().json.body || $input.first().json;
const events = body.events || [];
const keywords = ['下載', '衛教', '簡報'];

for (const ev of events) {
  if (ev.type === 'message' && ev.message?.type === 'text') {
    const text = (ev.message.text || '').trim();
    const matched = keywords.some(k => text.includes(k));
    if (matched) {
      return [{ json: { replyToken: ev.replyToken, userId: ev.source?.userId, messageText: text } }];
    }
  }
}
return [];

// ⑤ 組裝 LINE Flex Message（素材名稱+圖片）
const items = $input.all();
const replyToken = $('② 解析關鍵字').first().json.replyToken;

const bubbles = items.map((item, i) => {
  const j = item.json;
  const title = j.properties?.名稱?.title?.[0]?.plain_text || j.properties?.Name?.title?.[0]?.plain_text || j.title || '素材';
  const imgUrl = j.properties?.圖片?.url || j.properties?.封面?.files?.[0]?.file?.url || j.cover?.file?.url || '';
  const link = j.properties?.連結?.url || j.url || '';
  const formBase = $env.N8N_FORM_URL || 'https://your-n8n.com/form/xxx';
  const formUrl = `${formBase}?materialId=${j.id}&materialName=${encodeURIComponent(title)}`;

  return {
    type: 'bubble',
    hero: imgUrl ? { type: 'image', url: imgUrl, size: 'full', aspectRatio: '20:13', aspectMode: 'cover' } : undefined,
    body: {
      type: 'box',
      layout: 'vertical',
      contents: [
        { type: 'text', text: title, weight: 'bold', size: 'lg' },
        { type: 'button', action: { type: 'uri', label: '填寫表單領取', uri: formUrl }, style: 'primary' }
      ]
    }
  };
});

const flex = {
  type: 'carousel',
  contents: bubbles.length ? bubbles : [{ type: 'bubble', body: { type: 'box', layout: 'vertical', contents: [{ type: 'text', text: '目前暫無上線素材' }] } }]
};

return [{ json: { replyToken, flex } }];

